mapper.select:
select

,k.kecheng_name as kechengName
,c.chapter_name as chapterName
,r.resource_name as resourceName
,r.resource_type as resourceType
,y.yonghu_name as yonghuName
from study_progress a
left join kecheng k on a.kecheng_id = k.id
left join course_chapter c on a.chapter_id = c.id
left join course_resource r on a.resource_id = r.id
left join yonghu y on a.yonghu_id = y.id


        and a.kecheng_id = #{params.kechengId}


        and a.chapter_id = #{params.chapterId}


        and a.resource_id = #{params.resourceId}


        and a.yonghu_id = #{params.yonghuId}


        and k.jiaoshi_id = #{params.jiaoshiId}


order by a.${params.sort} ${params.order}
